#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;

__kernel void kernel_cpu(
    const int cores_arg,
    __global record *records,
    __global knode *knodes,
    const long knodes_elem,
    const int order,
    const long maxheight,
    const int count,
    __global long *currKnode,
    __global long *offset,
    __global int *keys,
    __global record *ans)
{
    int bid = get_global_id(0);
    int threadsPerBlock = order < 1024 ? order : 1024;

    if (bid >= count) return;

    long curr = currKnode[bid];
    long off = offset[bid];
    int key = keys[bid];

    for (long i = 0; i < maxheight; i++) {
        for (int t = 0; t < threadsPerBlock; t++) {
            int key_t = knodes[curr].keys[t];
            int key_t1 = knodes[curr].keys[t + 1];
            if (key_t <= key && key_t1 > key) {
                if (knodes[off].indices[t] < knodes_elem) {
                    off = knodes[off].indices[t];
                }
            }
        }
        curr = off;
    }
    currKnode[bid] = curr;
    offset[bid] = off;

    for (int t = 0; t < threadsPerBlock; t++) {
        if (knodes[curr].keys[t] == key) {
            ans[bid].value = records[knodes[curr].indices[t]].value;
        }
    }
}

